var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"다시 소개할게. 나는 제시카, 그리고 이쪽은 우리 소대원인 오르카.","JPN":"改めて紹介するわね。私はジェシカ、そしてこちらはうちの小隊員のオルカ。","ENG":"Let us introduce ourselves again. I'm Jessica, and this here is Orca. She's in my squad.","TWN":"我再介紹一次，我是潔西卡，這位是我們的小隊員 奧爾卡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"……오르카야. 반가워.","JPN":"……オルカ。よろしく。","ENG":"…I'm Orca. Nice to meet you.","TWN":"……我是奧爾卡，你好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"반갑습니다. 휴먼. 호라이즌입니다.","JPN":"はじめまして、ヒューマン。ホライズンです。","ENG":"Pleasure to make your acquaintance as well, humans. I am Horizon.","TWN":"人類，你們好，我是地平線。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 조우했던 오르카란 휴먼과 동일한 물품을 소지하고 계시는군요.","JPN":"私が以前遭遇したオルカというヒューマンと同じ物を所持していますね。","ENG":"I see you are in possession of the same object held by another human called Orca I once encountered.","TWN":"我也遇過一位叫奧爾卡的人，你們有一樣的東西呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동명이인이거나 친족 관계십니까?","JPN":"同名異人もしくは親族関係ですか？","ENG":"Any family relation? Or purely a coincidence?","TWN":"是同名同姓，還是你們有親戚關係？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 그렇게 이해해 준다면 설명할 수고는 덜 수 있겠지.","JPN":"まあ、そう理解してくれたら説明する手間が省けて助かるわね。","ENG":"Well, something like that. If it helps us save the trouble of explaining this long story.","TWN":"嗯，就當是那樣吧，這樣就不用再浪費口水多做解釋。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"관리국을 통해 태스크포스들에 공고가 내려왔어. 널 국제 수배한다는 내용이야.","JPN":"管理局を通じてタスクフォースカンパニーに通達が出ているわ。あんたを国際手配するという内容よ。","ENG":"The Administration has put out a notice to the TASKFORCEs. There's a Red Notice out for you.","TWN":"我們收到管理局針對特遣勢力發出的公告，內容是你現在是國際通緝犯。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"최근에 관리국이 개입할 만한 사건은 일으키지 않았습니다만.","JPN":"最近になって管理局が介入するような事件を起こした覚えはありませんが。","ENG":"I don't recall committing any offense recently that would warrant the Administration's involvement.","TWN":"我最近應該沒有做什麼需要管理局介入的事情。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"의료 지원을 왔던 사람들을 학살한 유력 용의자라던데? 뭐 짚이는 거 없어?","JPN":"医療支援に来た人たちを虐殺した最有力容疑者と聞いたわよ？　何か心当たりは？","ENG":"They say you're a prime suspect behind the massacre of medical aid workers. Got any hunches on what that's about?","TWN":"有人殘忍殺害來這裡義診的人，而你是嫌犯的可能性最大？你有想到什麼嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"학살?","JPN":"虐殺？","ENG":"Massacre?","TWN":"殘忍殺害？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"수술 중인 휴먼을 공격했기에 부상을 입히기는 했지만, 생명에 지장은 없었습니다.","JPN":"今手術中のヒューマンを攻撃していたので怪我をさせたのは事実ですが、命に別状はないはずです。","ENG":"It is true I injured them for attacking the human currently under surgery, but none of the injuries were fatal.","TWN":"因為他們攻擊目前正在手術中的人類，我才會傷害他們，但不至於要他們的性命。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"상황이 종결된 뒤 나타난 자가 벌인 짓입니다.","JPN":"状況が収束した後に現れた者の仕業です。","ENG":"Someone else appeared after the situation came under control. That's the true killer.","TWN":"這是在我之後出現的人做的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"네가 방금 한 말, 증명할 방법은 있어?","JPN":"あんたの今の言葉、証明できる方法はあるの？","ENG":"Is there a way to prove what you just said?","TWN":"有證據可以證明你剛才說的話嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 기억회로를 증거로 제출하면 됩니다.","JPN":"私の記憶回路を証拠として提出するだけの話です。","ENG":"I can submit my memory data as evidence.","TWN":"我的記憶迴路可以提交作為證據。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"글쎄, 범인으로 의심 받는 상황에 사람들이 순순히 믿어 줄까?","JPN":"どうかしら、犯人と疑われる立場なのに、それで信じてもらえるかしら。","ENG":"I don't know… Will people take your word for it when you're already the prime suspect?","TWN":"不好說，在懷疑你是嫌犯的情況下，大家可能不會乖乖地相信？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"요점은 이거야. 상황이 꼬이는 바람에 우리 회사도 널 직접적으로 도와 주진 못해.","JPN":"要するに、状況がこじれたせいでうちの会社もあんたを堂々と助けることはできなくなったの。","ENG":"Let me cut to the chase. Due to this recent… complication, our company can't help you directly anymore.","TWN":"重點是，因為情況有點複雜，我們公司也無法明目張膽地幫你。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 윌버란 놈이 지금 있는 위치가 저장된 데이터 메모리를 잃어 버리는 건……","JPN":"でも、ウィルバーって奴の位置情報が保存されたデータメモリーをうっかり無くしてしまうのは……","ENG":"However, if I were to misplace the memory drive that contains the current location of this Wilbur guy…","TWN":"不過我們弄丟了一個隨身碟，裡面好巧不巧，有那個叫韋爾伯的下落……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"업무상 과실로 처리되겠지?","JPN":"業務上過失扱いになるでしょうね？","ENG":"Well, I guess my only crime would be professional negligence!","TWN":"應該會當作是業務過失處理吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_THROW"},{"id":"L34_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"제시카. 나쁜 사람처럼 웃고 있다.","JPN":"ジェシカ。悪党みたいに笑っている。","ENG":"Jessica. You're smiling like a scoundrel.","TWN":"潔西卡，笑得令人發寒。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"충분히 큰 도움이 되었습니다. 고맙군요, 코핀 컴퍼니.","JPN":"十分助かります。ありがとうございます、コフィンカンパニー。","ENG":"That data would indeed prove most helpful. Coffin Company has my deepest thanks.","TWN":"謝謝科芬公司，幫了我大忙。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"공업지대 건너편 비행장에 우리가 타고 왔던 수송기가 있어.","JPN":"工業地帯の向こうの飛行場に私たちが乗ってきた輸送機があるわ。","ENG":"You'll find the plane we took on the airfield across the Industrial Area.","TWN":"工業區對面的機場，有停放一台我們剛才搭乘的運輸機。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"가는 길이 험할 테니 조심해, 고객님.","JPN":"行くまでの道のりはかなり険しいと思うから気を付けてね、お客様。","ENG":"It won't exactly be an easy journey out there, so be careful.","TWN":"這位客人，這條路會有點難走，路上小心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"잘 가. 호라이즌. 다음에 또 봐.","JPN":"またね、ホライズン。","ENG":"Bye, Horizon. See you again.","TWN":"地平線慢走，下次見。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……그래. 더 이상 발을 빼기 어렵다는 건 나도 알고 있어.","JPN":"……ああ。これ以上関わると手を引けなくなるのは俺もわかっている。","ENG":"…Yeah. I know it's too late to back out of this now.","TWN":"……嗯嗯，我也知道會很難脫身。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"합류하겠다고? 아니, 괜한 짓은……","JPN":"お前も合流する？　いや、余計なことは……","ENG":"You're going to join me? Really, that's not necessary…","TWN":"要跟我會合？會合要幹嘛……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"음. 이 얘기는 잠시 후에 다시 하지. 무작정 행동하지 마, 이유리.","JPN":"ああ、この話は後でしよう。むやみに行動するなよ、カスカベ。","ENG":"Hmm… Let's get back to this later. Don't do anything reckless, Yuri.","TWN":"嗯，這件事晚點再說。李悠麗，你先不要擅自行動。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이야기는 잘 됐나?","JPN":"話はうまくいったか？","ENG":"So, good talk?","TWN":"談完了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 얘기하는 사이 병원 분위기가 무척 어수선해졌군요.","JPN":"はい。話している間に病院の雰囲気がとても慌ただしくなりましたね。","ENG":"Yes. In the meantime, it seems a chaotic bustle has washed over the hospital.","TWN":"對，談到一半，醫院的氣氛好像變得很緊張。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"도시관리국에서 보낸 병력들이 이 일대를 봉쇄했어.","JPN":"都市管理局から派遣されてきた兵力がこの一帯を封鎖しているんだ。","ENG":"The City Managements' troops have sealed off the area.","TWN":"因為城市管理局派兵封鎖這一帶。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"누구 때문인지는 안 봐도 뻔하지.","JPN":"誰のせいなのか、聞くまでもないだろう。","ENG":"All because of you know who.","TWN":"想也知道是想抓誰。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 저도 수술이 끝나길 기다릴 수 없게 되었습니다. 휴먼.","JPN":"はい。私も手術が終わるまで待てなくなりました、ヒューマン。","ENG":"Yes. I too can no longer wait until the operation is completed, human.","TWN":"是，人類，我現在也無法等到瑞秋手術結束。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"수금을 하러 잠시 자리를 비울 예정입니다. 제가 없는 동안 레이첼을 부탁드립니다.","JPN":"集金の仕事があるのでしばらく席を外す予定です。私がいない間、レイチェルのことをお願いします。","ENG":"I must briefly leave this station to make a collection. Please take care of Rachel in my absence.","TWN":"我會暫時離開去收款，我不在的時候瑞秋就交給你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"부탁을 하려면 성의 표현이 있어야 한다는 말, 못 들어 봤나?","JPN":"お願いをするなら、誠意を見せるべきだとは思わないか？","ENG":"Haven't you ever heard of the expression, \\"you scratch my back and I'll scratch yours?\\"","TWN":"沒人跟你說過，拜託人的時候要展現誠意嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신을 신고하지 않은 걸로 대신하겠습니다. 민병대 강민우.","JPN":"あなたを通報しなかったことでチャラにします。民兵隊のマツダ・シュウイチさん。","ENG":"I believe not reporting you to the authorities should suffice. Kang Minwoo of the Militia.","TWN":"我的誠意就展現在我不會舉報你，民兵隊的姜民宇。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"역시 처음부터 알고 있었군. 레이첼과 가깝게 지내서인가.","JPN":"やはり最初から知っていたんだな。レイチェルと仲が良かったからか。","ENG":"So you knew all along after all. Is it because you've been spending a lot of time with Rachel?","TWN":"你從一開始就知道對吧。是因為我和瑞秋走太近嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 사고회로는 뉴로모픽 기반입니다. 레이첼이 판단 기준의 전부라고 오해하지 마시죠.","JPN":"私の思考回路はニューロモーフィック基盤です。レイチェルが判断基準のすべてだと誤解しないでください。","ENG":"My reasoning system is based on neuromorphic architecture. Do not make the mistake of thinking Rachel is the sole source of my assessments.","TWN":"我的思考迴路是以神經形態為基礎，請不要誤會瑞秋是我判斷的全部依據。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"판단 기준의 하나이긴 한가 보군. 네 말투에도 슬슬 적응이 되기 시작했어.","JPN":"判断基準の一つではあるんだな。あんたのその喋り方にもそろそろ慣れてきたところさ。","ENG":"Not the sole source, but it must be a part of it. I'm starting to catch on to the way you speak.","TWN":"那就是是判斷依據之一的意思吧，我慢慢抓到你說話的模式了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다녀와. 너무 오래 걸리지 않기만 바라지.","JPN":"行ってこい。あまり時間がかからないことを願っているぞ。","ENG":"Go do what you need to do, then. I just hope you won't take too long.","TWN":"去吧，希望你不要去太久。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 지금 이 구역은 민간인의 통행이 금지되어 있습니다.</color>","JPN":"<color=#ffd34c>ご案内します。現在この区域は民間人の通行が禁止されています。</color>","ENG":"<color=#ffd34c>Attention. This area is currently under martial control.</color>","TWN":"<color=#ffd34c>通知，現在這個區域禁止平民進出。</color>"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분께서는 군사 작전 종료까지 안전한 실내에서 대기하여 주십시오.</color>","JPN":"<color=#ffd34c>市民の皆様は軍事作戦の終了まで安全な室内で待機してください。</color>","ENG":"<color=#ffd34c>All civilians in the area are advised to shelter in place until the military operation is over.</color>","TWN":"<color=#ffd34c>請各位市民在安全的室內等候，待軍事作戰結束。</color>"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEFENSECORPS_NPC_NULL_NULL","text":{"KOREA":"수배자가 모습을 드러냈다!","JPN":"指名手配犯が姿を現した！","ENG":"They found her!","TWN":"通緝犯出現！"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEFENSECORPS_NPC_NULL_NULL","text":{"KOREA":"고등급 카운터일 수 있다는 첩보가 들어온 상태다! 전차를 앞세워 제압하라!","JPN":"高ランクカウンターかもしれないという情報が入ってきた！　戦車を盾にして制圧せよ！","ENG":"Intel suggests the suspect may be a high-tier Counter! Pin her down with the tanks!","TWN":"收到線報說可能是高級制裁者！派戰車在前面壓制她！"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"비켜 주시죠. 휴먼들. 저는 바쁜 기계입니다.","JPN":"退いてください、ヒューマン。私は忙しい機械です。","ENG":"Please clear the way, humans. I'm a busy machine.","TWN":"人類，請讓開，我有事要忙。"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"방해를 단념하지 않겠다면……","JPN":"邪魔をするつもりなら……","ENG":"Should you refuse to comply…","TWN":"若執意要擋路……"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>설득</color>해 드리겠습니다.","JPN":"<color=#ffd34c>説得</color>させていただきます。","ENG":"I'll have to take <color=#ffd34c>persuasive</color> measures.","TWN":"那我會<color=#ffd34c>說服</color>你們。"},"stage":{"bg":"HORIZON_07","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};